s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

TABLE_NAME = os.environ.get("TABLE_NAME", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "")
S3_BUCKET = os.environ.get("S3_BUCKET", "")


def lambda_handler(event, context):
    try:
        action = event.get("action", "noop")

        if action == "write_dynamodb":
            table = dynamodb.Table(TABLE_NAME)
            item = event.get("item", {})
            if not item:
                return {"statusCode": 400, "body": json.dumps({"message": "Missing item"})}
            table.put_item(Item=item)
            return {"statusCode": 200, "body": json.dumps({"message": "DynamoDB item written"})}

        if action == "publish_sns":
            message = event.get("message", "")
            if not SNS_TOPIC_ARN or not message:
                return {"statusCode": 400, "body": json.dumps({"message": "Missing SNS topic ARN or message"})}
            sns.publish(TopicArn=SNS_TOPIC_ARN, Message=message)
            return {"statusCode": 200, "body": json.dumps({"message": "SNS message published"})}

        if action == "send_sqs":
            message = event.get("message", "")
            if not SQS_QUEUE_URL or not message:
                return {"statusCode": 400, "body": json.dumps({"message": "Missing SQS queue URL or message"})}
            sqs.send_message(QueueUrl=SQS_QUEUE_URL, MessageBody=message)
            return {"statusCode": 200, "body": json.dumps({"message": "SQS message sent"})}

        if action == "put_s3":
            key = event.get("key", "")
            body = event.get("body", "")
            if not S3_BUCKET or not key:
                return {"statusCode": 400, "body": json.dumps({"message": "Missing S3 bucket or key"})}
            s3.put_object(Bucket=S3_BUCKET, Key=key, Body=body.encode("utf-8"))
            return {"statusCode": 200, "body": json.dumps({"message": "S3 object stored"})}

        return {"statusCode": 200, "body": json.dumps({"message": "No operation performed"})}

    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "AWS client error", "error": str(e)}),
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "Unhandled error", "error": str(e)}),
        }